    q(2,"After row reducing [A | I] to [I | B], what is B?",["A^T","A^2","A^(-1)","det(A)*I"],"When the left side becomes I, the right side is the inverse: B = A^(-1).",2),
    q(3,"Find the inverse of [[1,2],[3,7]] using row reduction. What is A^(-1)?",["[[7,-2],[-3,1]]","[[-7,2],[3,-1]]","[[1,-2],[-3,7]]","[[7,2],[3,1]]"],"det=7-6=1. A^(-1) = [[7,-2],[-3,1]]. Verify: [[1,2],[3,7]]*[[7,-2],[-3,1]] = [[1,0],[0,1]].",0),
    q(4,"During row reduction of [A|I], if you encounter a row of all zeros on the left side, what does this mean?",["Continue row reducing","A is invertible","A is singular and has no inverse","Swap with another row"],"A row of all zeros on the left means A cannot be reduced to I, so A is singular and has no inverse.",2),
