# 4.3 Adjoint Method
qs = [
    q(1,"The adjoint (classical adjoint) of a matrix A is:",["The transpose of the cofactor matrix","The conjugate transpose","The transpose of A","The determinant times I"],"adj(A) = (cofactor matrix)^T. It is used in the formula A^(-1) = adj(A)/det(A).",0),
    q(2,"The inverse formula using the adjoint is A^(-1) = ?",["adj(A) * det(A)","adj(A) / det(A)","det(A) / adj(A)","adj(A) + det(A)*I"],"A^(-1) = (1/det(A)) * adj(A), provided det(A) != 0.",1),
    q(3,"For A = [[a,b],[c,d]], adj(A) = ?",["[[d,-b],[-c,a]]","[[a,-b],[-c,d]]","[[-d,b],[c,-a]]","[[d,b],[c,a]]"],"For 2x2: adj(A) = [[d,-b],[-c,a]]. Swap diagonal entries, negate off-diagonal entries.",0),
    q(4,"What is adj(I) for the nxn identity matrix?",["The zero matrix","I itself","nI","I^T"],"Since the cofactor of each entry of I gives back I's structure, adj(I) = I.",1),
    q(5,"If det(A) = 3 and adj(A) = [[6,-3],[0,3]], what is A^(-1)?",["[[2,-1],[0,1]]","[[6,-3],[0,3]]","[[18,-9],[0,9]]","[[1/6,-1/3],[0,1/3]]"],"A^(-1) = adj(A)/det(A) = (1/3)*[[6,-3],[0,3]] = [[2,-1],[0,1]].",0),
    q(6,"The property A * adj(A) = det(A) * I holds for:",["Only 2x2 matrices","Only invertible matrices","All square matrices","Only diagonal matrices"],"A * adj(A) = det(A) * I is true for all square matrices, even singular ones (where both sides equal the zero matrix).",2),
    q(7,"For a 3x3 matrix, computing adj(A) requires finding how many cofactors?",["3","6","9","27"],"A 3x3 matrix has 9 entries, each with a cofactor. All 9 cofactors must be computed to form the cofactor matrix.",2),
    q(8,"What is the computational complexity of the adjoint method for an nxn inverse?",["O(n^2)","O(n^3)","O(n^4) or higher","O(n log n)"],"Computing n^2 cofactors, each requiring an (n-1)x(n-1) determinant, gives O(n^2 * n^2) = O(n^4) using cofactor expansion, or O(n^2 * (n-1)^3) using elimination for each.",2),
    q(9,"If A = [[2,1],[5,3]], what is adj(A)?",["[[3,-1],[-5,2]]","[[2,5],[1,3]]","[[-3,1],[5,-2]]","[[3,1],[5,2]]"],"For 2x2: swap diagonal (2,3)->(3,2), negate off-diagonal (1,5)->(-1,-5). adj(A) = [[3,-1],[-5,2]].",0),
    q(10,"For a singular matrix (det=0), what is adj(A)?",["Undefined","The zero matrix always","May be nonzero, but A*adj(A) = 0","The identity"],"A*adj(A) = det(A)*I = 0*I = 0. The adjugate itself may have nonzero entries, but the product with A is always zero.",2),
    q(11,"What does 'classical adjoint' mean?",["The transpose of the cofactor matrix, also called the adjugate","The complex conjugate of A","The adjoint operator in functional analysis","The transpose of A"],"The classical adjoint (adjugate) is the transpose of the matrix of cofactors. It should not be confused with the conjugate transpose used in other contexts.",0),
    q(12,"What does 'cofactor matrix' mean?",["The matrix where entry (i,j) is the cofactor C_{ij} = (-1)^(i+j) * M_{ij}","A matrix of all minors without signs","The inverse of A","The determinant matrix"],"The cofactor matrix replaces each entry a_{ij} with its cofactor C_{ij}. The adjugate is the transpose of this matrix.",0),
    q(13,"What is the 'adjugate' of a matrix?",["Another name for the classical adjoint: adj(A) = (cofactor matrix)^T","The absolute value of the determinant","The matrix of eigenvalues","A diagonal matrix"],"Adjugate is the modern mathematical term for the classical adjoint, to avoid confusion with the Hermitian adjoint.",0),
    q(14,"What does 'Cramer-adjoint connection' refer to?",["The entries of A^(-1) can be expressed as cofactors divided by det(A), connecting Cramer's rule to the adjugate","A formula for determinants using Cramer's name","A method for solving systems without determinants","The relationship between adj and trace"],"The (i,j) entry of A^(-1) is C_{ji}/det(A), which connects the adjugate formula to Cramer's rule for each variable.",0),
    q(15,"What does adj(AB) equal?",["adj(A)*adj(B)","adj(B)*adj(A)","adj(A)+adj(B)","(AB)^T"],"adj(AB) = adj(B)*adj(A), similar to how (AB)^(-1) = B^(-1)A^(-1). The order reverses.",1),
    q(16,"What is det(adj(A)) for an nxn matrix A?",["det(A)","det(A)^(n-1)","det(A)^n","1"],"det(adj(A)) = det(A)^(n-1). This follows from A*adj(A) = det(A)*I and taking determinants of both sides.",1),
    q(17,"What does 'symbolic inverse' mean?",["An inverse expressed in terms of symbolic entries (like a, b, c, d) rather than numbers","An inverse that does not exist","A graphical representation of the inverse","An approximate inverse"],"Using the adjugate method, A^(-1) can be written as a formula involving symbolic entries and determinants, useful for theoretical analysis.",0),
    q(18,"What is the adjugate of a diagonal matrix diag(a,b,c)?",["diag(bc, ac, ab)","diag(1/a, 1/b, 1/c)","diag(a,b,c)","The zero matrix"],"For a diagonal matrix, the cofactors give products of the other diagonal entries: adj = diag(bc, ac, ab).",0),
    q(19,"What does A^(-1) = adj(A)/det(A) reveal about the structure of inverses?",["Each entry of A^(-1) is a polynomial in the entries of A divided by det(A)","The inverse is always an integer matrix","The inverse has the same structure as A","The entries of A^(-1) are always positive"],"The adjugate entries are polynomials in the entries of A (sums of products of entries). Dividing by det(A) shows each entry of A^(-1) is a rational function of A's entries.",0),
    q(20,"What is the use of the adjugate in differential equations?",["The adjugate appears in the formula for the matrix exponential and in solving systems of ODEs","It is not used in differential equations","It replaces the derivative operator","It computes eigenvalues directly"],"In systems of ODEs dx/dt = Ax, the adjugate of (sI-A) appears in the Laplace transform solution and transfer functions.",0),
    q(21,"A cryptographer needs the inverse of [[3,5],[2,7]] modulo 26. det = 11, and 11^(-1) mod 26 = 19. Using adj(A) = [[7,-5],[-2,3]], what is A^(-1) mod 26?",["[[133,-95],[-38,57]] mod 26 = [[3,9],[14,5]]","[[7,-5],[-2,3]]","[[19,19],[19,19]]","Cannot be computed"],"A^(-1) = 19*[[7,-5],[-2,3]] mod 26 = [[133,-95],[-38,57]] mod 26 = [[3,9],[14,5]].",0),
    q(22,"An engineer needs to find the (2,1) entry of A^(-1) for a 3x3 matrix without computing the full inverse. Using the adjugate, this entry is:",["C_{12}/det(A), where C_{12} is the cofactor of a_{12}","C_{21}/det(A)","a_{21}/det(A)","The minor M_{21}"],"The (i,j) entry of A^(-1) = (1/det(A)) * adj(A)_{ij} = C_{ji}/det(A). For position (2,1): C_{12}/det(A).",0),
    q(23,"A physics student computes adj(A) for A = [[1,0,2],[0,1,0],[3,0,1]]. The cofactor C_{11} = det([[1,0],[0,1]]) = 1. Is this correct?",["Yes","No, C_{11} should include a sign factor","No, the wrong submatrix was used","C_{11} = -1"],"C_{11} = (-1)^(1+1) * det([[1,0],[0,1]]) = (+1)(1) = 1. The sign factor is +1 and the submatrix is correct.",0),
    q(24,"A control engineer has a 2x2 transfer function matrix. She uses the adjugate to find the inverse symbolically: if A = [[s+1, 2],[3, s+4]], what is adj(A)?",["[[s+4, -2],[-3, s+1]]","[[s+1, -2],[-3, s+4]]","[[s+4, 2],[3, s+1]]","[[s+4, 3],[2, s+1]]"],"For 2x2: swap diagonal entries and negate off-diagonal: adj = [[s+4, -2],[-3, s+1]].",0),
    q(25,"A mathematician proves that for any nxn matrix A, A*adj(A) = det(A)*I. If A is 3x3 with det(A)=5, what is A*adj(A)?",["5*I = [[5,0,0],[0,5,0],[0,0,5]]","I","adj(A)","25*I"],"A*adj(A) = det(A)*I = 5*I = diag(5,5,5).",0),
    q(26,"A numerical analyst compares the adjugate method to row reduction for a 10x10 matrix. Which is more efficient?",["Adjugate method (fewer operations)","Row reduction (O(n^3) vs O(n^4+) for adjugate)","Both are equally efficient","Neither can handle 10x10"],"Row reduction is O(n^3) while the adjugate method requires computing n^2 cofactors, making it O(n^4) or worse. Row reduction is far more efficient for large n.",1),
    q(27,"A statistics student needs A^(-1) for a symmetric positive definite matrix. Using the adjugate, she knows adj(A) is also symmetric. Why?",["Because cofactors of a symmetric matrix form a symmetric cofactor matrix, and transposing it preserves symmetry","All adjugates are symmetric","Symmetry is unrelated to the adjugate","Only for 2x2 matrices"],"For symmetric A, M_{ij} = M_{ji}, and the sign pattern (-1)^(i+j) is symmetric. So adj(A) is symmetric.",0),
    q(28,"A chemical engineer uses the formula adj(A)/det(A) for A = [[4,7],[2,6]]. det = 24-14 = 10. adj = [[6,-7],[-2,4]]. What is A^(-1)?",["[[0.6,-0.7],[-0.2,0.4]]","[[6,-7],[-2,4]]","[[4,7],[2,6]]","[[0.4,0.7],[0.2,0.6]]"],"A^(-1) = (1/10)*[[6,-7],[-2,4]] = [[0.6,-0.7],[-0.2,0.4]].",0),
    q(29,"A professor tells students: 'The adjugate method is theoretically important but practically limited.' She means:",["The formula gives insight into the structure of inverses but is computationally expensive for large matrices","The method only works for 2x2 matrices","The method is inaccurate","The method requires eigenvalues"],"The adjugate formula A^(-1) = adj(A)/det(A) provides a closed-form expression and is useful for proofs and small matrices, but it is O(n^4+) and impractical for large n.",0),
    q(30,"A robotics researcher needs to compute the inverse of a parameterized 3x3 matrix symbolically (entries are functions of joint angles). Which method is most suitable?",["Gaussian elimination with numerical values","The adjugate method, which gives a symbolic closed-form inverse","Iterative methods","LU decomposition"],"For symbolic computation, the adjugate method is ideal because it produces an exact formula in terms of the parameters, unlike numerical methods.",1)
]
write_quiz(4, "4.3", "Adjoint Method", qs)

